#!/bin/bash
# Dedicated Math Model Training
# Generated by scripts/train_dedicated_models.py

set -euo pipefail

MODEL="HuggingFaceTB/SmolLM2-135M"
OUTPUT="smollm2-135m-math-only"
EPOCHS=3
BATCH_SIZE=8
GRAD_ACCUM=4
MAX_STEPS=50000

echo "Training $OUTPUT from $MODEL"
echo "Config: Dedicated Math Model — trained exclusively on mathematical reasoning data"

# Use Axolotl or direct HF Trainer
# Option 1: Axolotl (recommended for efficient training)
# axolotl train configs/smollm2-135m-math-only.yml

# Option 2: Direct HuggingFace Trainer
python -m torch.distributed.run --nproc_per_node=1 scripts/train_single_skill.py \
    --model_name_or_path "$MODEL" \
    --output_dir "./outputs/$OUTPUT" \
    --per_device_train_batch_size $BATCH_SIZE \
    --gradient_accumulation_steps $GRAD_ACCUM \
    --max_steps $MAX_STEPS \
    --learning_rate 2e-05 \
    --warmup_steps 100 \
    --bf16 \
    --gradient_checkpointing \
    --save_strategy steps \
    --save_steps 5000 \
    --logging_steps 100 \
    --dataset_config "configs\math_model\dataset_config.json"

echo "Training complete. Model saved to ./outputs/$OUTPUT"
